#!/usr/bin/env bash
# trigger.sh — Trigger 决策助手 for 用 AI agent 赚钱 / agent 商业化 (创业 + 副业 + 咨询 + indie hacker).
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="用 AI agent 赚钱 / agent 商业化 (创业 + 副业 + 咨询 + indie hacker)"
TOPIC="Trigger"

usage() {
  cat <<EOF
trigger.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 10 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./trigger.sh             # interactive
  ./trigger.sh --dry-run   # walk through but no file
  ./trigger.sh --json      # JSON to stdout
  ./trigger.sh --explain   # show backing playbook rules + mental models
  ./trigger.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 Trigger 主题下的 playbook 规则组合成交互树。

基于 10 条规则:
  • 如果 D1 — 入行第一步: 学派定位 → 则 - **trigger**: 决定要做 monetize-agents 但还没选具体方向
  • 如果 D2 — PMF 验证: 不看 sign-ups, 看 paying customers → 则 - **trigger**: 产品上线后 30-90 天评估
  • 如果 D3 — 定价模型选择 → 则 - **trigger**: 准备开始收钱 (pre-launch 或 launch 后调整)
  • 如果 D4 — GTM 启动路径 → 则 - **trigger**: PMF 验证后 / 产品上线后 30 天
  • 如果 D5 — Scale 决策: $10K MRR 是分水岭 → 则 - **trigger**: 月营收稳定到 $10K (Indie) 或 $1M ARR (B2B) 量级
  • 如果 D6 — 工具选择: stage-appropriate → 则 - **trigger**: 选 tech stack / billing / GTM 工具
  • 如果 D7 — dogfood 标准 → 则 - **trigger**: 评估自己产品质量 / 决定 release
  • 如果 D8 — 监管 / 合规 → 则 - **trigger**: 准备接客户 / 收钱
  • 如果 D9 — 灰色边界自律 → 则 - **trigger**: 看到 "用 agent 赚 $X/月 自动化 spam / 内容农场" 帖子诱惑
  • 如果 D10 — 时效复盘节奏 → 则 - **trigger**: 每 3 月或重大行业事件 (新模型发布 / 主要 framework 升级 / 监管变化)

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "D1 — 入行第一步: 学派定位"
  "D2 — PMF 验证: 不看 sign-ups, 看 paying customers"
  "D3 — 定价模型选择"
  "D4 — GTM 启动路径"
  "D5 — Scale 决策: \$10K MRR 是分水岭"
  "D6 — 工具选择: stage-appropriate"
  "D7 — dogfood 标准"
  "D8 — 监管 / 合规"
  "D9 — 灰色边界自律"
  "D10 — 时效复盘节奏"
)
declare -a RULE_ACTIONS=(
  "- **trigger**: 决定要做 monetize-agents 但还没选具体方向"
  "- **trigger**: 产品上线后 30-90 天评估"
  "- **trigger**: 准备开始收钱 (pre-launch 或 launch 后调整)"
  "- **trigger**: PMF 验证后 / 产品上线后 30 天"
  "- **trigger**: 月营收稳定到 \$10K (Indie) 或 \$1M ARR (B2B) 量级"
  "- **trigger**: 选 tech stack / billing / GTM 工具"
  "- **trigger**: 评估自己产品质量 / 决定 release"
  "- **trigger**: 准备接客户 / 收钱"
  "- **trigger**: 看到 \"用 agent 赚 \$X/月 自动化 spam / 内容农场\" 帖子诱惑"
  "- **trigger**: 每 3 月或重大行业事件 (新模型发布 / 主要 framework 升级 / 监管变化)"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "trigger-decision"
fi
